$money=static fn(mixed $v):string=>'R$ '.number_format((float)$v,2,',','.');$date=static function(?string $v):string{if(!$v)return '—';$t=strtotime($v);return $t?date('d/m/Y H:i',$t):$v;};$statusLabel=['active'=>'Ativa','inactive'=>'Inativa','open'=>'Aberta','paid'=>'Paga','overdue'=>'Em atraso','cancelled'=>'Cancelada','success'=>'Enviado','error'=>'Erro','ignored'=>'Ignorado'];
$active=count(array_filter($rules,static fn(array $r):bool=>($r['status']??'')==='active'));$errors=count(array_filter($logs,static fn(array $l):bool=>($l['status']??'')==='error'));$upcoming=count($preview);
?>
<section class="admin-module-hero"><div><span class="eyebrow">Cobrança automática</span><h2>Régua de cobrança</h2><p>Defina quando avisar, por qual canal e quais ações automáticas podem ocorrer.</p></div><div class="admin-module-hero-actions"><form method="post" action="<?= View::e(Router::url('/billing-reminders/run')) ?>"><?= Csrf::input() ?><button class="btn btn-outline" type="submit">Processar agora</button></form><button class="btn btn-primary" type="button" data-reminder-open="new" data-toggle-panel="reminder-drawer">Nova regra</button></div></section>
