<section class="card admin-module-panel"><div class="section-heading"><div><span class="eyebrow">Regras de comunicação</span><h2>Avisos programados</h2><p>Os dias negativos representam antes do vencimento; zero é o dia; positivos são após.</p></div><span class="badge"><?= count($rules) ?> regra(s)</span></div><div class="admin-module-card-list compact-cards"><?php foreach($rules as $rule):?><article class="admin-record-card"><div class="admin-record-main"><span class="admin-record-mark is-reminder">D<?= (int)$rule['days_from_due'] ?></span><div class="admin-record-copy"><div class="admin-record-title-row"><div><h3><?= View::e($rule['label']) ?></h3><p><?= View::e($eventLabels[$rule['event_key']]??$rule['event_key']) ?></p></div><span class="badge badge-<?= View::e($rule['status']) ?>"><?= View::e($statusLabel[$rule['status']]??$rule['status']) ?></span></div><small class="admin-record-muted"><?= View::e($channelLabels[$rule['channel']]??$rule['channel']) ?> · <?= (int)$rule['days_from_due']===0?'no vencimento':((int)$rule['days_from_due']<0?abs((int)$rule['days_from_due']).' dia(s) antes':(int)$rule['days_from_due'].' dia(s) depois') ?></small></div></div><div class="admin-feature-tags"><?php if((int)($rule['auto_mark_overdue']??0)===1):?><span>Marca cobrança em atraso</span><?php endif;?><?php if((int)($rule['auto_suspend']??0)===1):?><span class="is-danger">Pode suspender assinatura</span><?php endif;?></div><details class="admin-inline-details"><summary>Ver mensagem</summary><p><?= nl2br(View::e($rule['message_template']??'')) ?></p></details><div class="admin-record-actions"><button class="btn btn-small btn-outline" type="button" data-toggle-panel="reminder-drawer" data-reminder-open="edit" data-id="<?= (int)$rule['id'] ?>" data-label="<?= View::e($rule['label']) ?>" data-days="<?= (int)$rule['days_from_due'] ?>" data-status="<?= View::e($rule['status']) ?>" data-event-key="<?= View::e($rule['event_key']) ?>" data-channel="<?= View::e($rule['channel']) ?>" data-auto-overdue="<?= (int)($rule['auto_mark_overdue']??0) ?>" data-auto-suspend="<?= (int)($rule['auto_suspend']??0) ?>" data-message="<?= View::e(rawurlencode((string)($rule['message_template']??''))) ?>">Editar regra</button></div></article><?php endforeach;?><?php if(!$rules):?><div class="empty-state">Nenhuma regra cadastrada.</div><?php endif;?></div></section>
<div class="admin-dashboard-grid"><section class="card"><div class="section-heading"><div><span class="eyebrow">Prévia operacional</span><h2>Próximas cobranças</h2></div><span class="badge"><?= count($preview) ?> cobrança(s)</span></div><div class="admin-log-list"><?php foreach($preview as $invoice):?><article class="admin-log-item"><div><strong><?= View::e($invoice['tenant_name']) ?> · <?= View::e($invoice['invoice_number']) ?></strong><span><?= View::e($money($invoice['amount'])) ?> · vence <?= View::e($date($invoice['due_date'])) ?></span><small><?= (int)$invoice['days_from_due']===0?'Hoje':((int)$invoice['days_from_due']<0?abs((int)$invoice['days_from_due']).' dia(s) antes':(int)$invoice['days_from_due'].' dia(s) após') ?></small></div><div><span class="badge badge-<?= View::e($invoice['status']) ?>"><?= View::e($statusLabel[$invoice['status']]??$invoice['status']) ?></span><?php $link=$invoice['external_checkout_url']?:$invoice['external_invoice_url'];if($link):?><a class="btn btn-small btn-outline" target="_blank" rel="noopener" href="<?= View::e($link) ?>">Abrir link</a><?php endif;?></div></article><?php endforeach;?><?php if(!$preview):?><div class="empty-state">Nenhuma cobrança no período.</div><?php endif;?></div></section><section class="card"><div class="section-heading"><div><span class="eyebrow">Histórico</span><h2>Últimos envios</h2></div><span class="badge"><?= count($logs) ?> registro(s)</span></div><div class="admin-log-list"><?php foreach($logs as $log):?><article class="admin-log-item is-<?= View::e($log['status']) ?>"><div><strong><?= View::e($log['tenant_name']??'—') ?> · <?= View::e($log['rule_label']??'Regra') ?></strong><span><?= View::e($log['invoice_number']??'—') ?> · <?= View::e($money($log['amount']??0)) ?></span><small><?= View::e($date($log['processed_at']??$log['created_at']??null)) ?></small></div><span class="badge badge-<?= View::e($log['status']) ?>"><?= View::e($statusLabel[$log['status']]??$log['status']) ?></span></article><?php endforeach;?><?php if(!$logs):?><div class="empty-state">Nenhum aviso processado.</div><?php endif;?></div></section></div>
<aside class="conversation-details conversation-drawer admin-form-drawer" id="reminder-drawer" aria-label="Configurar regra de cobrança" aria-modal="true" role="dialog"><div class="conversation-drawer-header"><div><span class="eyebrow" data-reminder-eyebrow>Nova regra</span><h2 data-reminder-title>Criar aviso automático</h2><p>Use linguagem clara e defina ações automáticas com cuidado.</p></div><button class="icon-button drawer-close" type="button" data-close-panel="reminder-drawer">×</button></div><div class="conversation-drawer-body"><form class="drawer-form" method="post" action="<?= View::e(Router::url('/billing-reminders/rules/save')) ?>" data-reminder-form><?= Csrf::input() ?><input type="hidden" name="id" value="0" data-reminder-field="id"><section class="drawer-section"><div class="drawer-form-grid"><label class="field drawer-span"><span>Nome da regra</span><input name="label" data-reminder-field="label" placeholder="3 dias antes do vencimento" required></label><label class="field"><span>Dias em relação ao vencimento</span><input type="number" name="days_from_due" value="-3" data-reminder-field="days_from_due"></label><label class="field"><span>Situação</span><select name="status" data-reminder-field="status"><option value="active">Ativa</option><option value="inactive">Inativa</option></select></label><label class="field drawer-span"><span>Evento</span><select name="event_key" data-reminder-field="event_key"><?php foreach($eventLabels as $key=>$label):?><option value="<?= View::e($key) ?>"><?= View::e($label) ?></option><?php endforeach;?></select></label><label class="field drawer-span"><span>Canal</span><select name="channel" data-reminder-field="channel"><?php foreach($channelLabels as $key=>$label):?><option value="<?= View::e($key) ?>"><?= View::e($label) ?></option><?php endforeach;?></select></label><label class="check-field drawer-span"><input type="checkbox" name="auto_mark_overdue" value="1" data-reminder-field="auto_mark_overdue"><span>Marcar a cobrança como em atraso quando aplicável</span></label><label class="check-field drawer-span"><input type="checkbox" name="auto_suspend" value="1" data-reminder-field="auto_suspend"><span>Suspender a assinatura quando aplicável</span></label><label class="field drawer-span"><span>Mensagem enviada</span><textarea name="message_template" rows="7" data-reminder-field="message_template">Olá, {{empresa}}. Sua cobrança {{invoice_number}} no valor de {{valor}} vence em {{vencimento}}. Link: {{link_pagamento}}</textarea><small class="field-hint">Variáveis: {{empresa}}, {{invoice_number}}, {{valor}}, {{vencimento}}, {{link_pagamento}}, {{dias}}</small></label></div></section><div class="drawer-savebar"><button class="btn btn-quiet" type="button" data-close-panel="reminder-drawer">Cancelar</button><button class="btn btn-primary" type="submit" data-reminder-submit>Salvar regra</button></div></form></div></aside>
